class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def is_subtree(root: TreeNode, sub: TreeNode) -> bool:
    def eq(x, y):
        if not x and not y:
            return True
        if not x or not y or x.val != y.val:
            return False
        return eq(x.left, y.left) and eq(x.right, y.right)
    if not sub:
        return True
    if not root:
        return False
    if eq(root, sub):
        return True
    return is_subtree(root.left, sub) or is_subtree(root.right, sub)

